"use strict";(globalThis.webpackChunktp_2025_t_23=globalThis.webpackChunktp_2025_t_23||[]).push([[7300],{2629:e=>{e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"documentationSidebar":[{"type":"link","href":"/TP2025-T23/docs/intro","label":"Dokument\xe1cia","docId":"intro","unlisted":false},{"type":"link","href":"/TP2025-T23/docs/team_documentation","label":"T\xedmov\xe1 dokument\xe1cia","docId":"team_documentation","unlisted":false},{"type":"category","label":"Data Science","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/TP2025-T23/docs/data-science/diagrams","label":"Diagramy","docId":"data-science/diagrams","unlisted":false},{"type":"link","href":"/TP2025-T23/docs/data-science/text_service","label":"EvilFlowers Text Service","docId":"data-science/text_service","unlisted":false}],"href":"/TP2025-T23/docs/category/data-science"},{"type":"category","label":"System Engineering","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/TP2025-T23/docs/system-engineering/dataverse_integration","label":"Dataverse Integration","docId":"system-engineering/dataverse_integration","unlisted":false}],"href":"/TP2025-T23/docs/category/system-engineering"},{"type":"category","label":"UX","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/TP2025-T23/docs/ux/search_analysis","label":"\ud83d\udd0d Anal\xfdza vyh\u013ead\xe1vania","docId":"ux/search_analysis","unlisted":false},{"type":"link","href":"/TP2025-T23/docs/ux/search_design","label":"\ud83d\udd0d N\xe1vrh vyh\u013ead\xe1vania","docId":"ux/search_design","unlisted":false},{"type":"link","href":"/TP2025-T23/docs/ux/intelligent_features","label":"\u2728 Inteligentn\xe9 funkcie","docId":"ux/intelligent_features","unlisted":false},{"type":"link","href":"/TP2025-T23/docs/ux/pdf_viewer","label":"\ud83d\udcc4 PDF Viewer","docId":"ux/pdf_viewer","unlisted":false},{"type":"link","href":"/TP2025-T23/docs/ux/loans","label":"\ud83d\udcc5 V\xfdpo\u017ei\u010dky","docId":"ux/loans","unlisted":false},{"type":"link","href":"/TP2025-T23/docs/ux/prototype","label":"\u2705 Prototyp","docId":"ux/prototype","unlisted":false}],"href":"/TP2025-T23/docs/category/ux"}]},"docs":{"data-science/diagrams":{"id":"data-science/diagrams","title":"Diagramy","description":"System component","sidebar":"documentationSidebar"},"data-science/text_service":{"id":"data-science/text_service","title":"EvilFlowers Text Service","description":"1. \xda\u010del syst\xe9mu","sidebar":"documentationSidebar"},"intro":{"id":"intro","title":"Dokument\xe1cia","description":"Na tejto str\xe1nke n\xe1jdete preh\u013ead v\u0161etk\xfdch v\xfdstupov n\xe1\u0161ho t\xedmu v r\xe1mci predmetu T\xedmov\xfd projekt. Cie\u013eom projektu bolo vylep\u0161i\u0165 syst\xe9m digit\xe1lnej akademickej kni\u017enice ELVIRA, ur\u010den\xfd pre Slovensk\xfa technick\xfa univerzitu v Bratislave.","sidebar":"documentationSidebar"},"system-engineering/dataverse_integration":{"id":"system-engineering/dataverse_integration","title":"Dataverse Integration","description":"Po publikovan\xed datasetu v Dataverse zapne hook do Evil Flowers API. Ten mus\xed vedie\u0165 savenut do Elviry, metadata o akviz\xedci\xed, odkaz na PDF v Dataverse a jednak inform\xe1ciu, odkia\u013e ten s\xfabor re\xe1lne je (Dataverse, S3, \u2026), a tieto \xfadaje potom v API norm\xe1lne returnova\u0165.","sidebar":"documentationSidebar"},"team_documentation":{"id":"team_documentation","title":"T\xedmov\xe1 dokument\xe1cia","description":"Mind map","sidebar":"documentationSidebar"},"ux/intelligent_features":{"id":"ux/intelligent_features","title":"\u2728 Inteligentn\xe9 funkcie","description":"Inteligentn\xe9 funkcie predstavuj\xfa s\xfabor funkcional\xedt, ktor\xe9 roz\u0161iruj\xfa Elviru nad r\xe1mec tradi\u010dn\xe9ho vyh\u013ead\xe1vania a \u010d\xedtania kn\xedh. N\xe1vrh vych\xe1dzal z predch\xe1dzaj\xfaceho pou\u017e\xedvate\u013esk\xe9ho testovania Elviry, testovania vyh\u013ead\xe1vania a n\xe1sledne aj pou\u017e\xedvate\u013esk\xfdch rozhovorov. N\xe1vrh bol tie\u017e ovplyvnen\xfd technick\xfdm smerovan\xedm t\xedmov\xe9ho projektu, najm\xe4 integr\xe1ciou s\xe9mantick\xe9ho vyh\u013ead\xe1vania. \xdalohou dizajnu bolo vyv\xedjan\xe9 technick\xe9 rie\u0161enie zmysluplne pretavi\u0165 do pou\u017e\xedvate\u013esk\xe9ho rozhrania. \u010cas\u0165 navrhnut\xfdch rie\u0161en\xed predstavuje frontendov\xe9 vylep\u0161enia. Celkovo by tieto funkcionality mali podpori\u0165 pou\u017e\xedvate\u013eov pri vyh\u013ead\xe1van\xed relevantnej literat\xfary, pochopen\xed komplexn\xfdch textov a orient\xe1cii vo ve\u013ekom mno\u017estve inform\xe1ci\xed.","sidebar":"documentationSidebar"},"ux/loans":{"id":"ux/loans","title":"\ud83d\udcc5 V\xfdpo\u017ei\u010dky","description":"Okrem priameho \u010d\xedtania kn\xedh v PDF \u010d\xedta\u010dke v Elvire si pou\u017e\xedvate\u013e m\xf4\u017ee niektor\xe9 knihy vypo\u017ei\u010da\u0165 digit\xe1lne. K po\u017ei\u010danej knihe m\xe1 ist\xfa dobu pr\xedstup, m\xf4\u017ee si ju kedyko\u013evek otvori\u0165 a \u010d\xedta\u0165. Digit\xe1lne v\xfdpo\u017ei\u010dky funguj\xfa podobne ako po\u017ei\u010diavanie fyzick\xfdch kn\xedh - kniha m\xe1 ur\u010dit\xfd po\u010det k\xf3pi\xed, pou\u017e\xedvate\u013e (\u010ditate\u013e) si knihu vypo\u017ei\u010dia na nieko\u013eko t\xfd\u017ed\u0148ov, m\xf4\u017ee ju pred\u010dasne vr\xe1ti\u0165 alebo pred\u013a\u017ei\u0165. Po potvrden\xed v\xfdpo\u017ei\u010dky sa vygeneruje link na stiahnutie s\xfaboru, ktor\xfd sa d\xe1 otvori\u0165 len v \u0161pecializovan\xfdch \u010d\xedta\u010dk\xe1ch (Thorium Reader). Na otvorenie s\xfaboru je tie\u017e potrebn\xe9 ma\u0165 nastaven\xfa pr\xedstupov\xfa fr\xe1zu. Funkcia v\xfdpo\u017ei\u010diek bola implementovan\xe1 na dev serveri Elviry a obsahovala nieko\u013eko nedostatkov a probl\xe9mov pou\u017eite\u013enosti, cel\xfd proces bol neintuit\xedvny a zlo\u017eit\xfd.","sidebar":"documentationSidebar"},"ux/pdf_viewer":{"id":"ux/pdf_viewer","title":"\ud83d\udcc4 PDF Viewer","description":"Ke\u010f\u017ee ve\u013ea navrhovan\xfdch inteligentn\xfdch funkci\xed sa t\xfdkalo PDF \u010d\xedta\u010dky, rozhodli sme sa presk\xfama\u0165 t\xfato \u010das\u0165 Elviry, zhodnoti\u0165 s\xfa\u010dasn\xfd dizajn, pou\u017eite\u013enos\u0165, identifikova\u0165 probl\xe9my a navrhn\xfa\u0165 inteligentn\xe9 funkcie tak, aby zlep\u0161ili pou\u017e\xedvate\u013esk\xfd z\xe1\u017eitok pri \u010d\xedtan\xed kn\xedh, pr\xedpadne tie\u017e vylep\u0161ili samotn\xfa \u010d\xedta\u010dku.","sidebar":"documentationSidebar"},"ux/prototype":{"id":"ux/prototype","title":"\u2705 Prototyp","description":"Na z\xe1ver sme vytvorili kompletn\xfd high-fidelity prototyp port\xe1lu Elvira vo Figme.","sidebar":"documentationSidebar"},"ux/search_analysis":{"id":"ux/search_analysis","title":"\ud83d\udd0d Anal\xfdza vyh\u013ead\xe1vania","description":"V predch\xe1dzaj\xfacej evalu\xe1cii Elviry bolo vyh\u013ead\xe1vanie ozna\u010den\xe9 ako katastrofa pou\u017eite\u013enosti, probl\xe9m s najv\xe4\u010d\u0161ou z\xe1va\u017enos\u0165ou, ktor\xfd je potrebn\xe9 napravi\u0165 \u010do najsk\xf4r. Cie\u013eom tejto anal\xfdzy bolo preto identifikova\u0165 probl\xe9my s pou\u017eite\u013enos\u0165ou a celkov\xfdm dizajnom vyh\u013ead\xe1vania. Analyzovali sme predch\xe1dzaj\xface testovanie Elviry, analytiku str\xe1nky, vykonali a vyhodnotili sme tie\u017e vlastn\xe9 testovanie. Poznatky z anal\xfdzy sme pou\u017eili pri n\xe1vrhu rie\u0161enia - redizajne vyh\u013ead\xe1vania.","sidebar":"documentationSidebar"},"ux/search_design":{"id":"ux/search_design","title":"\ud83d\udd0d N\xe1vrh vyh\u013ead\xe1vania","description":"User scenarios a user flows","sidebar":"documentationSidebar"}}}}')}}]);